class WebSocketServer:
    def __init__(self, port=8080):
        self.port = port
        self.server_socket = None
        self.clients = []
        self.handlers = {}
        
    def register_handler(self, action, callback):
        self.handlers[action] = callback
        
    def start(self, ssid, password):
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        
        if not wlan.isconnected():
            print('Connecting to network...')
            wlan.connect(ssid, password)
            while not wlan.isconnected():
                time.sleep(1)
        
        print('Network connected:', wlan.ifconfig())
        
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        
        print(f'WebSocket server started on port {self.port}')
        print(f'Connect to: ws://{wlan.ifconfig()[0]}:{self.port}/')
        
    def handle_websocket_handshake(self, client_socket):
        try:
            request = client_socket.recv(1024).decode('utf-8')
            
            lines = request.split('\r\n')
            headers = {}
            for line in lines[1:]:
                if ':' in line:
                    key, value = line.split(':', 1)
                    headers[key.strip()] = value.strip()
            
            if 'Sec-WebSocket-Key' not in headers:
                return False
            
            key = headers['Sec-WebSocket-Key']
            magic = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
            accept_key = ubinascii.b2a_base64(
                uhashlib.sha1((key + magic).encode()).digest()
            ).decode('utf-8').strip()
            
            response = (
                'HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                f'Sec-WebSocket-Accept: {accept_key}\r\n'
                '\r\n'
            )
            
            client_socket.send(response.encode('utf-8'))
            return True
        except Exception as e:
            print(f'Handshake error: {e}')
            return False
    
    def decode_websocket_frame(self, data):
        if len(data) < 2:
            return None
        
        byte1 = data[0]
        byte2 = data[1]
        
        fin = (byte1 & 0x80) != 0
        opcode = byte1 & 0x0F
        masked = (byte2 & 0x80) != 0
        payload_len = byte2 & 0x7F
        
        offset = 2
        
        if payload_len == 126:
            if len(data) < 4:
                return None
            payload_len = struct.unpack('>H', data[2:4])[0]
            offset = 4
        elif payload_len == 127:
            if len(data) < 10:
                return None
            payload_len = struct.unpack('>Q', data[2:10])[0]
            offset = 10
        
        if masked:
            if len(data) < offset + 4:
                return None
            masking_key = data[offset:offset + 4]
            offset += 4
        else:
            masking_key = None
        
        if len(data) < offset + payload_len:
            return None
        
        payload = bytearray(data[offset:offset + payload_len])
        
        if masked and masking_key:
            for i in range(len(payload)):
                payload[i] ^= masking_key[i % 4]
        
        return {
            'fin': fin,
            'opcode': opcode,
            'payload': bytes(payload)
        }
    
    def encode_websocket_frame(self, payload, opcode=1):
        frame = bytearray()
        
        frame.append(0x80 | opcode)
        
        payload_len = len(payload)
        if payload_len <= 125:
            frame.append(payload_len)
        elif payload_len <= 65535:
            frame.append(126)
            frame.extend(struct.pack('>H', payload_len))
        else:
            frame.append(127)
            frame.extend(struct.pack('>Q', payload_len))
        
        if isinstance(payload, str):
            payload = payload.encode('utf-8')
        frame.extend(payload)
        
        return bytes(frame)
    
    def send_to_client(self, client_socket, message):
        try:
            if isinstance(message, dict):
                message = json.dumps(message)
            frame = self.encode_websocket_frame(message)
            client_socket.send(frame)
            return True
        except Exception as e:
            print(f'Send error: {e}')
            return False
    
    def broadcast(self, message):
        disconnected = []
        for client in self.clients:
            if not self.send_to_client(client, message):
                disconnected.append(client)
        
        for client in disconnected:
            self.remove_client(client)
    
    def remove_client(self, client_socket):
        if client_socket in self.clients:
            self.clients.remove(client_socket)
            try:
                client_socket.close()
            except:
                pass
            print(f'Client disconnected. Active clients: {len(self.clients)}')
    
    def handle_client_message(self, client_socket, message):
        try:
            data = json.loads(message)
            
            if 'action' in data:
                action = data['action']
                
                if action in self.handlers:
                    result = self.handlers[action](data)
                    response = {'status': 'success', 'action': action, 'result': result}
                else:
                    response = {'status': 'error', 'message': f'Unknown action: {action}'}
                
                self.send_to_client(client_socket, response)
            else:
                response = {'status': 'error', 'message': 'No action specified'}
                self.send_to_client(client_socket, response)
                
        except json.JSONDecodeError:
            response = {'status': 'error', 'message': 'Invalid JSON'}
            self.send_to_client(client_socket, response)
        except Exception as e:
            response = {'status': 'error', 'message': str(e)}
            self.send_to_client(client_socket, response)
    
    def run(self):
        print('WebSocket server running...')
        
        while True:
            try:
                client_socket, addr = self.server_socket.accept()
                client_socket.setblocking(False)
                
                if self.handle_websocket_handshake(client_socket):
                    self.clients.append(client_socket)
                    print(f'New client connected: {addr}. Active clients: {len(self.clients)}')
                else:
                    client_socket.close()
                    
            except OSError:
                pass
            
            disconnected = []
            for client in self.clients:
                try:
                    data = client.recv(1024)
                    if data:
                        frame = self.decode_websocket_frame(data)
                        if frame:
                            if frame['opcode'] == 1:
                                message = frame['payload'].decode('utf-8')
                                self.handle_client_message(client, message)
                            elif frame['opcode'] == 8:
                                disconnected.append(client)
                            elif frame['opcode'] == 9:
                                pong = self.encode_websocket_frame(frame['payload'], opcode=10)
                                client.send(pong)
                    else:
                        disconnected.append(client)
                except OSError:
                    pass
                except Exception as e:
                    print(f'Client error: {e}')
                    disconnected.append(client)
            
            for client in disconnected:
                self.remove_client(client)
            
            time.sleep(0.01)


led = Pin(2, Pin.OUT)
relay = Pin(4, Pin.OUT)

def handle_turn_on(data):
    device = data.get('device', 'led')
    if device == 'led':
        led.on()
        return f'LED turned on'
    elif device == 'relay':
        relay.on()
        return f'Relay turned on'
    return f'Unknown device: {device}'

def handle_turn_off(data):
    device = data.get('device', 'led')
    if device == 'led':
        led.off()
        return f'LED turned off'
    elif device == 'relay':
        relay.off()
        return f'Relay turned off'
    return f'Unknown device: {device}'

def handle_toggle(data):
    device = data.get('device', 'led')
    if device == 'led':
        led.value(not led.value())
        return f'LED toggled to {led.value()}'
    elif device == 'relay':
        relay.value(not relay.value())
        return f'Relay toggled to {relay.value()}'
    return f'Unknown device: {device}'

def handle_status(data):
    return {
        'led': led.value(),
        'relay': relay.value()
    }

server = WebSocketServer(port=8080)
server.register_handler('turn_on', handle_turn_on)
server.register_handler('turn_off', handle_turn_off)
server.register_handler('toggle', handle_toggle)
server.register_handler('status', handle_status)

